39: func TestGRPCService(t *testing.T) {
40: 	t.Parallel()
41: 
42: 	defaultTimeout := 30 * time.Second
43: 	ctx, cancel := context.WithTimeout(context.Background(), defaultTimeout)
44: 	t.Cleanup(cancel)
45: 
46: 	address := filepath.Join(os.TempDir(), "kmsv2.sock")
47: 	plaintext := []byte("lorem ipsum dolor sit amet")
48: 	r := rand.New(rand.NewSource(time.Now().Unix()))
49: 	id, err := makeID(r.Read)
50: 	if err != nil {
51: 		t.Fatal(err)
52: 	}
53: 
54: 	kmsService := newBase64Service(id)
55: 	server := NewGRPCService(address, defaultTimeout, kmsService)
56: 	go func() {
57: 		if err := server.ListenAndServe(); err != nil {
58: 			panic(err)
59: 		}
60: 	}()
61: 	t.Cleanup(server.Shutdown)
62: 
63: 	client := newClient(t, address)
64: 
65: 	// make sure the gRPC server is up before running tests
66: ready:
67: 	for {
68: 		select {
69: 		case <-ctx.Done():
70: 			t.Fatalf("server failed to start in time: %v", ctx.Err())
71: 
72: 		default:
73: 			if done := func() bool {
74: 				ctx, cancel := context.WithTimeout(ctx, 3*time.Second)
75: 				defer cancel()
76: 
77: 				_, err := client.Status(ctx, &kmsapi.StatusRequest{})
78: 				if err != nil {
79: 					t.Logf("failed to get kms status: %v", err)
80: 				}
81: 
82: 				return err == nil
83: 			}(); done {
84: 				break ready
85: 			}
86: 			time.Sleep(time.Second)
87: 		}
88: 	}
89: 
90: 	t.Run("should be able to encrypt and decrypt through unix domain sockets", func(t *testing.T) {
91: 		t.Parallel()
92: 
93: 		encRes, err := client.Encrypt(ctx, &kmsapi.EncryptRequest{
94: 			Plaintext: plaintext,
95: 			Uid:       id,
96: 		})
97: 		if err != nil {
98: 			t.Fatal(err)
99: 		}
100: 
101: 		if bytes.Equal(plaintext, encRes.Ciphertext) {
102: 			t.Fatal("plaintext and ciphertext shouldn't be equal!")
103: 		}
104: 
105: 		decRes, err := client.Decrypt(ctx, &kmsapi.DecryptRequest{
106: 			Ciphertext:  encRes.Ciphertext,
107: 			KeyId:       encRes.KeyId,
108: 			Annotations: encRes.Annotations,
109: 			Uid:         id,
110: 		})
111: 		if err != nil {
112: 			t.Fatal(err)
113: 		}
114: 
115: 		if !bytes.Equal(decRes.Plaintext, plaintext) {
116: 			t.Errorf("want: %q, have: %q", plaintext, decRes.Plaintext)
117: 		}
118: 	})
119: 
120: 	t.Run("should return status data", func(t *testing.T) {
121: 		t.Parallel()
122: 
123: 		status, err := client.Status(ctx, &kmsapi.StatusRequest{})
124: 		if err != nil {
125: 			t.Fatal(err)
126: 		}
127: 
128: 		if status.Healthz != "ok" {
129: 			t.Errorf("want: %q, have: %q", "ok", status.Healthz)
130: 		}
131: 		if len(status.KeyId) == 0 {
132: 			t.Errorf("want: len(keyID) > 0, have: %d", len(status.KeyId))
133: 		}
134: 		if status.Version != version {
135: 			t.Errorf("want %q, have: %q", version, status.Version)
136: 		}
137: 	})
138: }
