144: 		address,
145: 		grpc.WithTransportCredentials(insecure.NewCredentials()),
146: 		grpc.WithDialer(func(addr string, t time.Duration) (net.Conn, error) {
147: 			return net.Dial("unix", addr)
148: 		}),
149: 	)
150: 	if err != nil {
151: 		t.Fatal(err)
152: 	}
153: 
154: 	t.Cleanup(func() { _ = cnn.Close() })
155: 
156: 	return kmsapi.NewKeyManagementServiceClient(cnn)
157: }
