\t"go.etcd.io/etcd/client/v3/naming/resolver"
\t"go.etcd.io/etcd/pkg/v3/grpctesting"
\t"go.etcd.io/etcd/tests/v3/framework/integration"
)

func testEtcdGRPCResolver(t *testing.T, lbPolicy string) {
\t// Setup two new dummy stub servers
\tpayloadBody := []byte{'1'}
\ts1 := grpctesting.NewDummyStubServer(payloadBody)
\tif err := s1.Start(nil); err != nil {
\t\tt.Fatal("failed to start dummy grpc server (s1)", err)
\t}
\tdefer s1.Stop()

\ts2 := grpctesting.NewDummyStubServer(payloadBody)
\tif err := s2.Start(nil); err != nil {
\t\tt.Fatal("failed to start dummy grpc server (s2)", err)
\t}
\tdefer s2.Stop()

\t// Create new cluster with endpoint manager with two endpoints
\tclus := integration.NewCluster(t, &integration.ClusterConfig{Size: 3})
\tdefer clus.Terminate(t)

\tem, err := endpoints.NewManager(clus.Client(0), "foo")
\tif err != nil {
\t\tt.Fatal("failed to create EndpointManager", err)
\t}

\te1 := endpoints.Endpoint{Addr: s1.Addr()}
\te2 := endpoints.Endpoint{Addr: s2.Addr()}

\terr = em.AddEndpoint(t.Context(), "foo/e1", e1)
\tif err != nil {
\t\tt.Fatal("failed to add foo", err)
\t}

\terr = em.AddEndpoint(t.Context(), "foo/e2", e2)
\tif err != nil {
\t\tt.Fatal("failed to add foo", err)
\t}

\tb, err := resolver.NewBuilder(clus.Client(1))
\tif err != nil {
\t\tt.Fatal("failed to new resolver builder", err)
\t}

\t// Create connection with provided lb policy
\tconn, err := grpc.Dial("etcd:///foo", grpc.WithTransportCredentials(insecure.NewCredentials()), grpc.WithResolvers(b), //nolint:staticcheck // TODO: remove for a supported version
\t\tgrpc.WithDefaultServiceConfig(fmt.Sprintf(`{"loadBalancingPolicy":"%s"}`, lbPolicy)))
\tif err != nil {
\t\tt.Fatal("failed to connect to foo", err)
\t}
\tdefer conn.Close()

\t// Send an initial request that should go to e1
\tc := testpb.NewTestServiceClient(conn)
\tresp, err := c.UnaryCall(t.Context(), &testpb.SimpleRequest{}, grpc.WaitForReady(true))
\tif err != nil {
\t\tt.Fatal("failed to invoke rpc to foo (e1)", err)
\t}
\tif resp.GetPayload() == nil || !bytes.Equal(resp.GetPayload().GetBody(), payloadBody) {
\t\tt.Fatalf("unexpected response from foo (e1): %s", resp.GetPayload().GetBody())
\t}

\t// Send more requests
\tlastResponse := []byte{'1'}
\ttotalRequests := 3500
\tfor i := 1; i < totalRequests; i++ {
\t\tresp, err := c.UnaryCall(t.Context(), &testpb.SimpleRequest{}, grpc.WaitForReady(true))
\t\tif err != nil {
\t\t\tt.Fatal("failed to invoke rpc to foo", err)
\t\t}

\t\tt.Logf("Response: %v", string(resp.GetPayload().GetBody()))

\t\trequire.NotNilf(t, resp.GetPayload(), "unexpected response from foo: %s", resp.GetPayload().GetBody())
\t\tlastResponse = resp.GetPayload().GetBody()
\t}

\t// If the load balancing policy is pick first then return payload should equal number of requests
\tt.Logf("Last response: %v", string(lastResponse))
\tif lbPolicy == "pick_first" {
\t\trequire.Equalf(t, "3500", string(lastResponse), "unexpected total responses from foo: %s", lastResponse)
\t}

\t// If the load balancing policy is round robin we should see roughly half total requests served by each server
\tif lbPolicy == "round_robin" {
\t\tresponses, err := strconv.Atoi(string(lastResponse))
\t\trequire.NoErrorf(t, err, "couldn't convert to int: %s", lastResponse)

\t\t// Allow 25% tolerance as round robin is not perfect and we don't want the test to flake
\t\texpected := float64(totalRequests) * 0.5
\t\tassert.InEpsilonf(t, expected, float64(responses), 0.25, "unexpected total responses from foo: %s", lastResponse)
\t}
}

// TestEtcdGrpcResolverPickFirst mimics scenarios described in grpc_naming.md doc.
func TestEtcdGrpcResolverPickFirst(t *testing.T) {
\tintegration.BeforeTest(t)

\t// Pick first is the default load balancer policy for grpc-go
\ttestEtcdGRPCResolver(t, "pick_first")
}

// TestEtcdGrpcResolverRoundRobin mimics scenarios described in grpc_naming.md doc.
func TestEtcdGrpcResolverRoundRobin(t *testing.T) {
\tintegration.BeforeTest(t)

\t// Round robin is a common alternative for more production oriented scenarios
\ttestEtcdGRPCResolver(t, "round_robin")
}
""")

