// Prober is an interface that defines the Probe function for doing GRPC readiness/liveness/startup checks.
type Prober interface {
\tProbe(host, service string, port int, timeout time.Duration) (probe.Result, string, error)
}

type grpcProber struct {
}

// New Prober for execute grpc probe
func New() Prober {
\treturn grpcProber{}
}

// Probe executes a grpc call to check the liveness/readiness/startup of container.
// Returns the Result status, command output, and errors if any.
// Any failure is considered as a probe failure to mimic grpc_health_probe tool behavior.
// err is always nil
func (p grpcProber) Probe(host, service string, port int, timeout time.Duration) (probe.Result, string, error) {
\tv := version.Get()

\topts := []grpc.DialOption{
\t\tgrpc.WithUserAgent(fmt.Sprintf("kube-probe/%s.%s", v.Major, v.Minor)),
\t\tgrpc.WithBlock(),
\t\tgrpc.WithTransportCredentials(insecure.NewCredentials()), //credentials are currently not supported
\t\tgrpc.WithContextDialer(func(ctx context.Context, addr string) (net.Conn, error) {
\t\t\treturn probe.ProbeDialer().DialContext(ctx, "tcp", addr)
\t\t}),
\t}

\tctx, cancel := context.WithTimeout(context.Background(), timeout)

\tdefer cancel()

\taddr := net.JoinHostPort(host, fmt.Sprintf("%d", port))
\tconn, err := grpc.DialContext(ctx, addr, opts...)

\tif err != nil {
\t\tif err == context.DeadlineExceeded {
\t\t\tklog.V(4).ErrorS(err, "failed to connect grpc service due to timeout", "addr", addr, "service", service, "timeout", timeout)
\t\t\treturn probe.Failure, fmt.Sprintf("timeout: failed to connect service %q within %v: %+v", addr, timeout, err), nil
\t\t} else {
\t\t\tklog.V(4).ErrorS(err, "failed to connect grpc service", "service", addr)
\t\t\treturn probe.Failure, fmt.Sprintf("error: failed to connect service at %q: %+v", addr, err), nil
\t\t}
\t}

\tdefer func() {
\t\t_ = conn.Close()
\t}()

\tclient := grpchealth.NewHealthClient(conn)

\tresp, err := client.Check(metadata.NewOutgoingContext(ctx, make(metadata.MD)), &grpchealth.HealthCheckRequest{
\t\tService: service,
\t})

\tif err != nil {
\t\tstat, ok := status.FromError(err)
\t\tif ok {
\t\t\tswitch stat.Code() {
\t\t\tcase codes.Unimplemented:
\t\t\t\tklog.V(4).ErrorS(err, "server does not implement the grpc health protocol (grpc.health.v1.Health)", "addr", addr, "service", service)
\t\t\t\treturn probe.Failure, fmt.Sprintf("error: this server does not implement the grpc health protocol (grpc.health.v1.Health): %s", stat.Message()), nil
\t\t\tcase codes.DeadlineExceeded:
\t\t\t\tklog.V(4).ErrorS(err, "rpc request not finished within timeout", "addr", addr, "service", service, "timeout", timeout)
\t\t\t\treturn probe.Failure, fmt.Sprintf("timeout: health rpc did not complete within %v", timeout), nil
\t\t\tdefault:
\t\t\t\tklog.V(4).ErrorS(err, "rpc probe failed")
\t\t\t}
\t\t} else {
\t\t\tklog.V(4).ErrorS(err, "health rpc probe failed")
\t\t}

\t\treturn probe.Failure, fmt.Sprintf("error: health rpc probe failed: %+v", err), nil
\t}

\tif resp.GetStatus() != grpchealth.HealthCheckResponse_SERVING {
\t\treturn probe.Failure, fmt.Sprintf("service unhealthy (responded with %q)", resp.GetStatus().String()), nil
\t}

\treturn probe.Success, fmt.Sprintf("service healthy"), nil
}
""")

