"""Create remaining original source files in /workspace."""
import os

def write(path, content):
    full = os.path.join('/workspace', path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, 'w') as f:
        f.write(content)
    print(f"  wrote {full}")

