// NewGRPCService returns an envelope.Service which use gRPC to communicate the remote KMS provider.
func NewGRPCService(ctx context.Context, endpoint, providerName string, callTimeout time.Duration) (kmsservice.Service, error) {
\tklog.V(4).InfoS("Configure KMS provider", "endpoint", endpoint)

\taddr, err := util.ParseEndpoint(endpoint)
\tif err != nil {
\t\treturn nil, err
\t}

\ts := &gRPCService{callTimeout: callTimeout}
\ts.connection, err = grpc.Dial(
\t\taddr,
\t\tgrpc.WithAuthority("localhost"),
\t\tgrpc.WithTransportCredentials(insecure.NewCredentials()),
\t\tgrpc.WithDefaultCallOptions(grpc.WaitForReady(true)),
\t\tgrpc.WithContextDialer(
\t\t\tfunc(context.Context, string) (net.Conn, error) {
\t\t\t\t// Ignoring addr and timeout arguments:
\t\t\t\t// addr - comes from the closure
\t\t\t\tc, err := net.DialUnix(unixProtocol, nil, &net.UnixAddr{Name: addr})
\t\t\t\tif err != nil {
\t\t\t\t\tklog.ErrorS(err, "failed to create connection to unix socket", "addr", addr)
\t\t\t\t} else {
\t\t\t\t\tklog.V(4).InfoS("Successfully dialed Unix socket", "addr", addr)
\t\t\t\t}
\t\t\t\treturn c, err
\t\t\t}),
\t\tgrpc.WithChainUnaryInterceptor(recordMetricsInterceptor(providerName)),
\t)

\tif err != nil {
\t\treturn nil, fmt.Errorf("failed to create connection to %s, error: %v", endpoint, err)
\t}

\ts.kmsClient = kmsapi.NewKeyManagementServiceClient(s.connection)

\tgo func() {
\t\tdefer utilruntime.HandleCrashWithContext(ctx)

\t\t<-ctx.Done()
\t\t_ = s.connection.Close()
\t}()

\treturn s, nil
}

// Decrypt a given data string to obtain the original byte data.
func (g *gRPCService) Decrypt(ctx context.Context, uid string, req *kmsservice.DecryptRequest) ([]byte, error) {
\tctx, cancel := context.WithTimeout(ctx, g.callTimeout)
\tdefer cancel()

\trequest := &kmsapi.DecryptRequest{
\t\tCiphertext:  req.Ciphertext,
\t\tUid:         uid,
\t\tKeyId:       req.KeyID,
\t\tAnnotations: req.Annotations,
\t}
\tresponse, err := g.kmsClient.Decrypt(ctx, request)
\tif err != nil {
\t\treturn nil, err
\t}
\treturn response.Plaintext, nil
}

// Encrypt bytes to a string ciphertext.
func (g *gRPCService) Encrypt(ctx context.Context, uid string, plaintext []byte) (*kmsservice.EncryptResponse, error) {
\tctx, cancel := context.WithTimeout(ctx, g.callTimeout)
\tdefer cancel()

\trequest := &kmsapi.EncryptRequest{
\t\tPlaintext: plaintext,
\t\tUid:       uid,
\t}
\tresponse, err := g.kmsClient.Encrypt(ctx, request)
\tif err != nil {
\t\treturn nil, err
\t}
\treturn &kmsservice.EncryptResponse{
\t\tCiphertext:  response.Ciphertext,
\t\tKeyID:       response.KeyId,
\t\tAnnotations: response.Annotations,
\t}, nil
}

// Status returns the status of the KMSv2 provider.
func (g *gRPCService) Status(ctx context.Context) (*kmsservice.StatusResponse, error) {
\tctx, cancel := context.WithTimeout(ctx, g.callTimeout)
\tdefer cancel()

\trequest := &kmsapi.StatusRequest{}
\tresponse, err := g.kmsClient.Status(ctx, request)
\tif err != nil {
\t\treturn nil, err
\t}
\treturn &kmsservice.StatusResponse{Version: response.Version, Healthz: response.Healthz, KeyID: response.KeyId}, nil
}

func recordMetricsInterceptor(providerName string) grpc.UnaryClientInterceptor {
\treturn func(ctx context.Context, method string, req, reply interface{}, cc *grpc.ClientConn, invoker grpc.UnaryInvoker, opts ...grpc.CallOption) error {
\t\tnowFunc := GetNowFunc(providerName)
\t\tstart := nowFunc()
\t\trespErr := invoker(ctx, method, req, reply, cc, opts...)
\t\telapsed := nowFunc().Sub(start)
\t\tmetrics.RecordKMSOperationLatency(providerName, method, elapsed, respErr)
\t\treturn respErr
\t}
}
